properties.scriptContent:
param()
$ErrorActionPreference = 'Continue'

$ctx        = Get-AzContext
$subId      = $ctx.Subscription.Id
$tenantId   = $ctx.Tenant.Id
$ws         = $env:workspaceName
$rg         = $env:resourceGroupName
$enabledIds = $env:enabledConnectors -split ',' | Where-Object { $_ -ne '' }

Write-Output ('=== Conosco Sentinel Init | workspace: ' + $ws + ' | tenant: ' + $tenantId + ' ===')
Write-Output ('Connectors selected: ' + ($enabledIds -join ', '))

# --- Acquire management token (version-safe: Az 14+ returns a SecureString) ---
$tokenResult = Get-AzAccessToken -ResourceUrl 'https://management.azure.com'
if ($tokenResult.Token -is [System.Security.SecureString]) {
    $tok = [System.Net.NetworkCredential]::new('', $tokenResult.Token).Password
} else {
    $tok = $tokenResult.Token
}

$h   = @{ Authorization = ('Bearer ' + $tok); 'Content-Type' = 'application/json' }
$apv = '2023-02-01-preview'
$si  = 'https://management.azure.com/subscriptions/' + $subId +
       '/resourceGroups/' + $rg +
       '/providers/Microsoft.OperationalInsights/workspaces/' + $ws +
       '/providers/Microsoft.SecurityInsights'

function Invoke-SentinelPut($path, $body) {
    try {
        $null = Invoke-RestMethod -Uri ($si + $path) -Method Put -Headers $h -Body ($body | ConvertTo-Json -Depth 10)
        Write-Output ('  [OK]   ' + $path.Split('?')[0].TrimStart('/'))
    } catch {
        Write-Warning ('  [FAIL] ' + $path.Split('?')[0].TrimStart('/') + ' | ' + $_.Exception.Message)
    }
}

# ------------------------------------------------------------------
# 0. Wait for the deployment identity's role assignment to propagate.
#    Azure RBAC is eventually consistent; the script can start before
#    Contributor is usable, causing 403s on the first calls.
# ------------------------------------------------------------------
Write-Output '--- Waiting for RBAC propagation ---'
$probeUri = $si + '/alertRules?api-version=' + $apv
$ready = $false
for ($i = 1; $i -le 20; $i++) {
    try {
        $null = Invoke-RestMethod -Uri $probeUri -Method Get -Headers $h -ErrorAction Stop
        $ready = $true
        Write-Output ('  RBAC ready (attempt ' + $i + ')')
        break
    } catch {
        $code = $null
        if ($_.Exception.Response) { $code = $_.Exception.Response.StatusCode.value__ }
        Write-Output ('  Attempt ' + $i + ': not ready (' + $code + '), waiting 15s...')
        Start-Sleep -Seconds 15
    }
}
if (-not $ready) {
    Write-Warning '  RBAC did not confirm within ~5 min; proceeding (some steps may fail).'
}

# ------------------------------------------------------------------
# 1. UEBA
# ------------------------------------------------------------------
Write-Output '--- UEBA ---'
Invoke-SentinelPut ('/settings/Ueba?api-version=' + $apv) @{
    kind = 'Ueba'; etag = '*'
    properties = @{ dataSources = @('AuditLogs', 'AzureActivity', 'SigninLogs', 'SecurityEvent') }
}

# ------------------------------------------------------------------
# 2. Data connectors (filtered to selected list)
# ------------------------------------------------------------------
Write-Output '--- Data connectors ---'
$connectors = @(
    @{ id = 'Office365'
       body = @{ kind = 'Office365'; properties = @{ dataTypes = @{
           exchange = @{ state = 'enabled' }; sharePoint = @{ state = 'enabled' }; teams = @{ state = 'enabled' } }}}},
    @{ id = 'OfficeIRM'
       body = @{ kind = 'OfficeIRM'; properties = @{ tenantId = $tenantId
           dataTypes = @{ alerts = @{ state = 'enabled' }}}}},
    @{ id = 'MicrosoftCloudAppSecurity'
       body = @{ kind = 'MicrosoftCloudAppSecurity'; properties = @{ tenantId = $tenantId
           dataTypes = @{ alerts = @{ state = 'enabled' }; discoveryLogs = @{ state = 'enabled' }}}}},
    @{ id = 'MicrosoftDefenderAdvancedThreatProtection'
       body = @{ kind = 'MicrosoftDefenderAdvancedThreatProtection'; properties = @{ tenantId = $tenantId
           dataTypes = @{ alerts = @{ state = 'enabled' }}}}},
    @{ id = 'AzureAdvancedThreatProtection'
       body = @{ kind = 'AzureAdvancedThreatProtection'; properties = @{ tenantId = $tenantId
           dataTypes = @{ alerts = @{ state = 'enabled' }}}}},
    @{ id = 'OfficeATP'
       body = @{ kind = 'OfficeATP'; properties = @{ tenantId = $tenantId
           dataTypes = @{ alerts = @{ state = 'enabled' }}}}},
    @{ id = 'MicrosoftThreatIntelligence'
       body = @{ kind = 'MicrosoftThreatIntelligence'; properties = @{ tenantId = $tenantId
           dataTypes = @{ microsoftEmergingThreatFeed = @{ state = 'enabled'; lookbackPeriod = '2024-01-01T00:00:00.000Z' }}}}},
    @{ id = 'MicrosoftThreatProtection'
       body = @{ kind = 'MicrosoftThreatProtection'; properties = @{ tenantId = $tenantId
           dataTypes = @{ alerts = @{ state = 'enabled' }; incidents = @{ state = 'enabled' }}}}},
    @{ id = 'AzureActiveDirectory'
       body = @{ kind = 'AzureActiveDirectory'; properties = @{ tenantId = $tenantId
           dataTypes = @{
               signinLogs                   = @{ state = 'enabled' }
               auditLogs                    = @{ state = 'enabled' }
               nonInteractiveUserSignInLogs = @{ state = 'enabled' }
               serviceAccountSignInLogs     = @{ state = 'enabled' }
               aadRiskyUsers                = @{ state = 'enabled' }
               userRiskEvents               = @{ state = 'enabled' }
           }}}},
    @{ id = 'AzureActiveDirectoryIdentityProtection'
       body = @{ kind = 'AzureActiveDirectoryIdentityProtection'; properties = @{ tenantId = $tenantId
           dataTypes = @{ alerts = @{ state = 'enabled' }}}}}
)

foreach ($c in $connectors) {
    if ($c.id -notin $enabledIds) {
        Write-Output ('  [SKIP] ' + $c.id)
        continue
    }
    Invoke-SentinelPut ('/dataConnectors/' + $c.id + '?api-version=' + $apv) $c.body
}

# Azure Activity - subscription-level diagnostic setting
if ('AzureActivity' -in $enabledIds) {
    try {
        $wsId = '/subscriptions/' + $subId + '/resourceGroups/' + $rg +
                '/providers/Microsoft.OperationalInsights/workspaces/' + $ws
        $actBody = @{
            properties = @{
                workspaceId = $wsId
                logs = @(
                    @{ category = 'Administrative'; enabled = $true }
                    @{ category = 'Security';       enabled = $true }
                    @{ category = 'ServiceHealth';  enabled = $true }
                    @{ category = 'Alert';          enabled = $true }
                    @{ category = 'Recommendation'; enabled = $true }
                    @{ category = 'Policy';         enabled = $true }
                    @{ category = 'Autoscale';      enabled = $true }
                    @{ category = 'ResourceHealth'; enabled = $true }
                )
            }
        } | ConvertTo-Json -Depth 10
        $actUri = 'https://management.azure.com/subscriptions/' + $subId +
                  '/providers/microsoft.insights/diagnosticSettings/cns-sentinel-activity?api-version=2021-05-01-preview'
        $null = Invoke-RestMethod -Uri $actUri -Method Put -Headers $h -Body $actBody
        Write-Output '  [OK]   AzureActivity diagnostic setting'
    } catch {
        Write-Warning ('  [FAIL] AzureActivity -- ' + $_.Exception.Message +
            ' | Ensure deployment identity has Monitoring Contributor at subscription scope, or enable manually.')
    }
} else {
    Write-Output '  [SKIP] AzureActivity'
}

# ------------------------------------------------------------------
# 3. Playbook permissions
# ------------------------------------------------------------------
Write-Output '--- Playbook permissions ---'
try {
    $sp = Get-AzADServicePrincipal -DisplayName 'Azure Security Insights' -ErrorAction SilentlyContinue
    if ($null -ne $sp) {
        $lacRoleId = '87a39d53-fc1b-424a-814c-f7e04687dc9e'
        $rgScope   = '/subscriptions/' + $subId + '/resourceGroups/' + $rg
        $existing  = Get-AzRoleAssignment -ObjectId $sp.Id -RoleDefinitionId $lacRoleId -Scope $rgScope -ErrorAction SilentlyContinue
        if (-not $existing) {
            $null = New-AzRoleAssignment -ObjectId $sp.Id -RoleDefinitionId $lacRoleId -Scope $rgScope
            Write-Output '  [OK]   Logic App Contributor granted to Azure Security Insights SP'
        } else {
            Write-Output '  [OK]   Logic App Contributor already assigned'
        }
    } else {
        Write-Warning '  [WARN] Azure Security Insights SP not found - grant manually via Sentinel > Settings > Playbook permissions'
    }
} catch {
    Write-Warning ('  [FAIL] Logic App permissions: ' + $_.Exception.Message)
}

Write-Output '=== Conosco Sentinel Init complete ==='
